var e=JSON.parse(`[{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저건......?","JPN":"あれは……？","ENG":"What's that?","TWN":"那是……？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍이군요. 자연적으로 발생하는 건 드문 일인데......","JPN":"次元の暴風ですね。自然発生は稀ですが……","ENG":"A dimensional storm. It rarely occurs naturally.","TWN":"是次元風暴呢。會自然發生還真是稀奇……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"더 가까이 접근하면 위험할 수도 있습니다.","JPN":"これ以上近づくのは危険です。","ENG":"We shouldn't get closer. It's too dangerous.","TWN":"但我們繼續靠近的話，可能會發生危險。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이상하군.","JPN":"妙だな。","ENG":"This is strange.","TWN":"奇怪。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍이 발생하는 곳은 일반적으로 고순도 이터니움 광맥이 있는 곳이지.","JPN":"次元の暴風は、一般的に高純度エタニウムの鉱脈がある場所に発生する。","ENG":"Dimensional storms usually occur around high-purity Eternium veins.","TWN":"會發生次元風暴的地方，一般都會有高純度永恆之金的礦脈吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"채굴 업체들이라면 모를까, 전술 평가작전을 진행하기에 적절한 장소는 아니야.","JPN":"採掘業者ならともかく、戦術評価作戦の遂行にふさわしい場所ではない。","ENG":"This may be a popular spot among mining companies, but it's not a good place to carry out tactical evaluations.","TWN":"是開採業者就算了，但這裡並不適合進行戰術評估作戰啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어째서 우리를 이런 곳으로 부른 거지?","JPN":"どうして我々をこんな場所に呼んだんだ？","ENG":"Why did they call us here?","TWN":"怎麼會把我們叫到這種地方來？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"메이데이! 메이데이!","JPN":"メーデー！　メーデー！","ENG":"Mayday! Mayday!","TWN":"緊急求救！緊急求救！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L19_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"여기는 정보부 파견대 지휘관, 블랙 버드!","JPN":"こちら情報局支隊指揮官のブラックバード！","ENG":"This is Commander Blackbird, of the Intelligence Agency detached force!","TWN":"這裡是情報部派遣隊指揮官，黑鳥！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"현재 차원 폭풍으로부터 나타난 대규모 침식체 무리로부터 공격 받고 있다!","JPN":"現在、次元の暴風から現れた侵食体の大群に攻撃されている！","ENG":"We're under attack by a large horde of C.O.s that came out of a dimensional storm!","TWN":"我們現在正遭受從次元風暴中出現的大規模侵蝕體群的攻擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L21_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"즉시 구원을 요청한다!","JPN":"ただちに救援を要請する！","ENG":"We need help right away!","TWN":"請求立即救援！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L22_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"용병이든 뭐든 좋아! 이 통신을 듣는 자는 누구라도 좋으니까 당장 도와달라고!","JPN":"傭兵だろうが何だろうが関係ない！\\nこの連絡を聞いたなら、誰でもいいから今すぐ助けてほしい！","ENG":"I don't care if you're mercenaries. If you can hear me, please come help us!","TWN":"傭兵也好，什麼都行！無論是誰聽到這則通信，請馬上來幫我們！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_30"},{"id":"L25_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"제기랄, 차원 폭풍이 이렇게 심한데 통신 연결이 되겠어?!","JPN":"くそっ、次元の暴風がこんなに吹き荒れている状態で\\n通信なんて繋がるのかよ！？","ENG":"Drat, this dimensional storm is too strong! There's no way anyone can hear us!","TWN":"該死的，次元風暴這麼嚴重，通信還連接的上嗎？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_RIFLE_FIRE"},{"id":"L26_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럼 그냥 앉아서 죽을 생각인가?!","JPN":"なら、このまま座して死を待つのか！？","ENG":"But we can't just sit here and wait to die!","TWN":"不然怎麼辦，坐著等死嗎？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"우린 전투부대가 아니라 정보부대라고!","JPN":"俺らは戦闘部隊ではなく情報部隊なんだ！","ENG":"We're not combatants—we're intelligence agents!","TWN":"我們不是戰鬥部隊，是情報部隊啊！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"저 정도의 침식체 무리와 싸우는 건 자살행위야!","JPN":"あの規模の侵食体どもと戦うのは自殺行為だぞ！","ENG":"We can't fight so many C.O.s on our own!","TWN":"和這個數量的侵蝕體群戰鬥，根本就是自殺行為！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"그럼 차라리 도망을 가자고!","JPN":"なら、いっそのこと逃げようぜ！","ENG":"Then, let's run away!","TWN":"那還不如逃跑呢！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"말이 되는 소릴 해!","JPN":"バカ言うな！　","ENG":"Are you crazy?","TWN":"說點人話好不！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"우리가 도망치면 차원 폭풍 안으로 들어간 선발대는 어떻게 돌아오라고?!","JPN":"俺らが逃げ出したら、次元の暴風の中に入った選抜隊はどうやって帰還する！？","ENG":"What about the advance party that went into the storm? Are you going to leave it behind?","TWN":"我們逃走的話，進入次元風暴的先頭部隊要怎麼回來啊？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사령관님!","JPN":"司令官！","ENG":"Commander!","TWN":"司令官！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래, 우리가 접선할 파견대가 아마 저 친구들인 것 같군.","JPN":"ああ、我々を待つ隊はあの連中のようだな。","ENG":"Yes, they must be the detached force we're supposed to meet.","TWN":"沒錯，那些朋友大概就是要和我們會合的派遣隊。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"거 쌤통이네.","JPN":"……いい気味だわ。","ENG":"That serves them right.","TWN":"活該。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"항상 콧대만 높아서 거들먹거리고 다니더니 진짜 위기에 대처할 능력은 없나 보지?","JPN":"いつも偉そうな態度をとるくせに、いざという時に対処する力はないようね。","ENG":"They always thought they were better than us. Look who's begging for help right now.","TWN":"整天目中無人，趾高氣揚的，真的遇到危機就沒有應對能力了是吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아, 개인적인 감정 때문에 위험에 빠진 전우들을 모른 척 하면 곤란한데.","JPN":"シルビア、個人的な感情に流されて危険に瀕した戦友にそっぽを向くのは困る。","ENG":"Sylvia, put your personal feelings aside. They're our comrades and we need to help them.","TWN":"希爾維亞，如果因為私人恩怨，對陷入困境的戰友視而不見的話，我會很困擾的。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그, 그냥 말이 그렇다는 거야, 말이!","JPN":"い、いや、ちょっと口が滑っただけよ！　","ENG":"I-I was just saying.","TWN":"我、我只是嘴上說說而已嘛！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"다, 당연히 도와야지.","JPN":"た、助けるに決まってるわ。","ENG":"O-of course, we should help.","TWN":"我、我當然會去救他們啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 의욕을 보여주니 참 든든하군. 그럼 통신을 연결해 주렴.","JPN":"君がやる気を見せてくれるとは実に心強いな。\\nさて、連絡をとってくれたまえ。","ENG":"I'm glad you're being so enthusiastic. Now, put them on the line.","TWN":"妳能夠展現出有幹勁的樣子，那還真是令人放心呢。幫我連接通信吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 알겠어......","JPN":"わ、わかった……","ENG":"O-okay...","TWN":"知、知道了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ONLY_KYLE_WALL_DAMAGE_DOWN"},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"여기는 USSA 뉴 오하이오, 전술 평가부대인 델타세븐 사령관 마리아 안토노프 소장이다.","JPN":"こちらUSSAニューオハイオ。\\n戦術評価部隊のデルタセブンの司令官、マリア・アントノフ少将だ。","ENG":"This is Major General Maria Antonov, of the tactical evaluation unit Delta Seven, from the USSA New Ohio.","TWN":"這裡是USSA新俄亥俄，我是戰鬥評估部隊，第七三角洲部隊的司令官瑪麗亞·安東諾夫少將。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"긴급 구원 요청을 접수했다. 지금부터 교전 수칙에 따라 아군을 지원하겠다.","JPN":"緊急救援要請を受け付けた。\\nこれより交戦規則に従って、味方支援を開始する。","ENG":"We've received your emergency MEDEVAC request. We'll follow the engagement protocol to support you.","TWN":"接收到緊急救援請求。現在開始，將根據交戰守則支援友軍。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};